 */
function extractSection(output: string, marker: string): string | null {
  const idx = output.indexOf(marker);
  if (idx === -1) return null;

  // Get the text after the marker, up to the next "---" delimiter or step marker
  const afterMarker = output.substring(idx + marker.length);
  // Find the next step boundary (act prefixes with | for step output)
  const lines = afterMarker.split("\n");
