  let braceDepth = 0;
  let started = false;

  for (const line of lines) {
    // Strip act's "| " prefix if present
    const stripped = line.replace(/^[|]\s?/, "").trim();
    if (!started && stripped.startsWith("{")) {
      started = true;
    }
    if (started) {
